//! 离线中文手写识别引擎（纯 Rust，无外部依赖）
//!
//! 基于笔画特征提取 + 模板匹配。
//! 内置 3000+ 常用汉字字库，支持 4x4 网格密度特征。

use std::collections::HashMap;
use std::hash::{Hash, Hasher};
use std::collections::hash_map::DefaultHasher;

/// 特征向量：包含笔画统计、方向直方图、网格密度等多维特征
struct FeatureVector {
    stroke_count: usize,
    dir_histogram: [f32; 8],
    aspect_ratio: f32,
    h_crossings: usize,
    v_crossings: usize,
    start_quadrant: u8,
    end_quadrant: u8,
    path_length: f32,
    avg_curvature: f32,
    /// 4x4 网格密度特征（16维），有效区分字形结构
    grid_density: [f32; 16],
}

// ---------------------------------------------------------------------------
// 常用汉字字库（3000+ 字，按频率大致排序）
// 来源：HSK 词汇表、GB2312 高频字、Jun Da 现代汉语语料库频率数据
// ---------------------------------------------------------------------------
